class AuthManager(private val context: Context) {

    private val sharedPreferences = context.getSharedPreferences("AuthData", Context.MODE_PRIVATE)
    private val AUTH_TOKEN_KEY = "authToken"
    private val USER_ID_KEY = "userId"

    fun saveAuthData(authToken: String, userId: Int) {
        sharedPreferences.edit().apply {
            putString(AUTH_TOKEN_KEY, authToken)
            putInt(USER_ID_KEY, userId)
            apply()
        }
    }

    fun getAuthToken(): String? {
        return sharedPreferences.getString(AUTH_TOKEN_KEY, null)
    }

    fun getUserId(): Int {
        return sharedPreferences.getInt(USER_ID_KEY, -1)
    }

    fun clearAuthData() {
        sharedPreferences.edit().clear().apply()
    }
}